// searchUsersHandler searches for users by username in the PostgreSQL database.
// It expects a 'username' query parameter and returns a JSON array of matching users.
func searchUsersHandler(w http.ResponseWriter, r *http.Request) {
	// 1. Get username from query parameter
	usernameQuery := r.URL.Query().Get("username")
	if usernameQuery == "" {
		http.Error(w, "username query parameter is required", http.StatusBadRequest)
		return
	}

	// 2. Prepare and execute the SQL query
	// Using ILIKE for case-insensitive search and wildcards for partial matching
	// e.g., if usernameQuery is "ali", it will match "alice", "Alister", etc.
	stmt, err := db.Prepare("SELECT id, username, email FROM users WHERE username ILIKE '%' || $1 || '%'")
	if err != nil {
		log.Printf("Error preparing statement: %v", err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}
	defer stmt.Close()

	rows, err := stmt.Query(usernameQuery)
	if err != nil {
		log.Printf("Error executing query for username '%s': %v", usernameQuery, err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}
	defer rows.Close()

	// 3. Scan results into a slice of User structs
	var users []User
	for rows.Next() {
		var u User
		if err := rows.Scan(&u.ID, &u.Username, &u.Email); err != nil {
			log.Printf("Error scanning user row: %v", err)
			http.Error(w, "Internal server error", http.StatusInternalServerError)
			return
		}
		users = append(users, u)
	}

	// Check for any errors encountered during row iteration
	if err = rows.Err(); err != nil {
		log.Printf("Error after iterating rows: %v", err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	// 4. Return results as JSON
	w.Header().Set("Content-Type", "application/json")
	if err := json.NewEncoder(w).Encode(users); err != nil {
		log.Printf("Error encoding JSON response: %v", err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}
}

